parameters.jsCode:
const items = $input.all();

// Pterodactyl
const pteroData = items.find(i => i.json.data && Array.isArray(i.json.data));
const servers = pteroData?.json?.data || [];
const totalServers = servers.length;

// Hub stats (may fail)
const hubData = items.find(i => i.json.total_users !== undefined);
const totalUsers = hubData?.json?.total_users || 'N/A';
const onlineNow = hubData?.json?.online_now || 'N/A';
const newToday = hubData?.json?.new_today || 'N/A';

// Uptime
const uptimeData = items.find(i => i.json.heartbeatList || i.json.uptimeList);
let uptimeSummary = 'N/A';
if (uptimeData?.json?.uptimeList) {
  const vals = Object.values(uptimeData.json.uptimeList);
  const avg = vals.length > 0 ? (vals.reduce((a, b) => a + (b?.uptime24 || 0), 0) / vals.length * 100).toFixed(1) : 'N/A';
  uptimeSummary = `${avg}% avg`;
}

const today = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{ json: {
  today,
  totalServers,
  totalUsers,
  onlineNow,
  newToday,
  uptimeSummary,
  timestamp: new Date().toISOString()
}}];

